import sqlite3
from contextlib import contextmanager

@contextmanager
def transaction(db):
    try:
        yield db.cursor()
        db.commit()
    except Exception as e:
        db.rollback()
        raise e

class AccountBalanceManager:
    def __init__(self, db_name):
        self.conn = sqlite3.connect(db_name)
        self.cursor = self.conn.cursor()

    def update_balance(self, account_id, amount):
        with transaction(self.conn) as cursor:
            cursor.execute("SELECT balance FROM accounts WHERE id = ?", (account_id,))
            current_balance = cursor.fetchone()[0]
            new_balance = current_balance + amount
            cursor.execute("UPDATE accounts SET balance = ? WHERE id = ?", (new_balance, account_id))

    def get_balance(self, account_id):
        with transaction(self.conn) as cursor:
            cursor.execute("SELECT balance FROM accounts WHERE id = ?", (account_id,))
            return cursor.fetchone()[0]

# Example usage
balance_manager = AccountBalanceManager('accounts.db')
balance_manager.update_balance(1, 100)
